// issue-classifier-prompt.js
// N8N Code node — Phase 2: Issue Triage & Routing
// Receives a GitHub issue webhook payload and builds a structured AI prompt
// for classification, priority assignment, and channel routing.

// ── 1. Extract issue metadata from the webhook payload ───────────────────────
const payload = $input.all()[0].json.body;
const issue = payload.issue;
const repo = payload.repository.full_name;

const issueMeta = {
  issue_number: issue.number,
  issue_title: issue.title,
  issue_body: issue.body ?? "",
  issue_author: issue.user.login,
  issue_url: issue.html_url,
  existing_labels: (issue.labels ?? []).map((l) => l.name),
  repo_full_name: repo,
};

// ── 2. System instruction ────────────────────────────────────────────────────
const system_prompt =
  "You are a senior engineering manager triaging GitHub issues. " +
  "Classify each issue and assign a priority. " +
  "Respond ONLY with valid JSON, no markdown fences.";

// ── 3. Build user message ────────────────────────────────────────────────────
const user_prompt = `## GitHub Issue for Triage

**Issue #${issueMeta.issue_number}:** ${issueMeta.issue_title}
**Author:** ${issueMeta.issue_author}
**Repository:** ${issueMeta.repo_full_name}
**Existing labels:** ${issueMeta.existing_labels.length > 0 ? issueMeta.existing_labels.join(", ") : "none"}

### Issue Body
${issueMeta.issue_body || "(empty)"}

## Classification Task

1. **Classify** this issue into exactly one category:
   - **bug** — something is broken or not working as expected
   - **feature** — a request for new functionality or enhancement
   - **question** — the author is asking for help or clarification
   - **documentation** — missing, incorrect, or unclear docs
   - **security** — a vulnerability, exposure, or security concern

2. **Assign priority** using these definitions:
   - **P0** — system down or security breach; requires immediate response
   - **P1** — major functionality broken; needs fix within 24 hours
   - **P2** — important but not urgent; schedule for next sprint
   - **P3** — nice to have / minor improvement

3. **Route** to the appropriate Slack channel:
   - bug → #incidents
   - security → #incidents (always P0 or P1)
   - feature → #product
   - question → #support
   - documentation → #engineering

Respond with **only** a JSON object (no markdown, no extra text) containing exactly these fields:

{
  "classification": "bug|feature|question|documentation|security",
  "priority": "P0|P1|P2|P3",
  "reasoning": "1 sentence explaining the classification",
  "suggested_labels": ["array of GitHub labels to apply"],
  "route_to": "#channel-name based on the routing rules above"
}`;

// ── 4. Return prompts + pass-through metadata ────────────────────────────────
return [
  {
    json: {
      system_prompt,
      user_prompt,
      issue_metadata: issueMeta,
    },
  },
];

// issue-router.js
// N8N Code node — Phase 2: Issue Triage & Routing
// Parses the AI classification response, determines routing, and builds
// a Slack Block Kit message tailored to the target channel.

// ── 1. Collect input ─────────────────────────────────────────────────────────
const input = $input.all()[0].json;
const meta = input.issue_metadata;

// Extract AI text from Anthropic response format
let aiText = "";
try {
  aiText = input.content[0].text;
} catch (_) {
  // fallback: the AI response may already be a flat string
  aiText = typeof input.ai_response === "string" ? input.ai_response : JSON.stringify(input.ai_response ?? "");
}

// ── 2. Parse the AI response (tolerant of markdown fences) ───────────────────
let classification;
try {
  let raw = aiText;
  raw = raw.replace(/```(?:json)?\s*/gi, "").replace(/```/g, "").trim();
  classification = JSON.parse(raw);
} catch (err) {
  console.error("Failed to parse AI classification:", err.message);

  return [
    {
      json: {
        slack_blocks: [
          { type: "header", text: { type: "plain_text", text: `⚠️ Issue #${meta.issue_number}: Classification Failed`, emoji: true } },
          { type: "section", text: { type: "mrkdwn", text: "Automatic classification failed — *manual triage needed*." } },
          { type: "actions", elements: [{ type: "button", text: { type: "plain_text", text: "View Issue", emoji: true }, url: meta.issue_url, style: "danger" }] },
        ],
        slack_text: `⚠️ Issue #${meta.issue_number} (${meta.issue_title}) — classification failed, manual triage needed: ${meta.issue_url}`,
        classification: "unknown",
        priority: "P2",
        route_channel: "#incidents",
        labels_to_apply: [],
        ...meta,
      },
    },
  ];
}

// ── 3. Determine prefix emoji and channel ────────────────────────────────────
const type = classification.classification ?? "bug";
const priority = classification.priority ?? "P2";
const channel = classification.route_to ?? "#incidents";

const prefixMap = {
  bug: "🐛",
  security: "🔒",
  feature: "💡",
  question: "❓",
  documentation: "📄",
};
const emoji = prefixMap[type] ?? "📋";

const isUrgent = (type === "bug" || type === "security") && (priority === "P0" || priority === "P1");
const urgentPrefix = isUrgent ? "🚨 " : "";

// ── 4. Build Slack Block Kit blocks ──────────────────────────────────────────
const blocks = [];

// Header
blocks.push({
  type: "header",
  text: {
    type: "plain_text",
    text: `${urgentPrefix}${emoji} Issue #${meta.issue_number}: ${meta.issue_title}`,
    emoji: true,
  },
});

// @channel mention for P0/P1 bugs/security
if (isUrgent) {
  blocks.push({
    type: "section",
    text: {
      type: "mrkdwn",
      text: `<!channel> *${priority} ${type.toUpperCase()}* needs immediate attention!`,
    },
  });
}

// AI reasoning
blocks.push({
  type: "section",
  text: {
    type: "mrkdwn",
    text: classification.reasoning,
  },
});

// Metadata fields
blocks.push({
  type: "section",
  fields: [
    { type: "mrkdwn", text: `*Author:*\n${meta.issue_author}` },
    { type: "mrkdwn", text: `*Classification:*\n${emoji} ${type}` },
    { type: "mrkdwn", text: `*Priority:*\n${priority}` },
    { type: "mrkdwn", text: `*Routed to:*\n${channel}` },
  ],
});

// Suggested labels
const labels = classification.suggested_labels ?? [];
if (labels.length > 0) {
  blocks.push({
    type: "context",
    elements: [
      {
        type: "mrkdwn",
        text: `🏷️ *Labels:* ${labels.map((l) => "`" + l + "`").join("  ")}`,
      },
    ],
  });
}

// Divider + action button
blocks.push({ type: "divider" });
blocks.push({
  type: "actions",
  elements: [
    {
      type: "button",
      text: { type: "plain_text", text: "View Issue", emoji: true },
      url: meta.issue_url,
      style: isUrgent ? "danger" : "primary",
    },
  ],
});

// ── 5. Plain-text fallback ───────────────────────────────────────────────────
const slack_text = `${urgentPrefix}${emoji} Issue #${meta.issue_number} (${meta.issue_title}) — ${type} ${priority} → ${channel}: ${meta.issue_url}`;

// ── 6. Return everything downstream nodes need ──────────────────────────────
return [
  {
    json: {
      slack_blocks: blocks,
      slack_text,
      classification: type,
      priority,
      route_channel: channel,
      labels_to_apply: labels,
      reasoning: classification.reasoning,
      raw_ai_response: classification,
      // Pass through issue metadata for Supabase insert
      issue_number: meta.issue_number,
      issue_title: meta.issue_title,
      issue_author: meta.issue_author,
      issue_url: meta.issue_url,
      repo_full_name: meta.repo_full_name,
      ai_model_used: input.model ?? "unknown",
    },
  },
];

const error = $input.all()[0].json;
const msg = error.execution?.error?.message ?? "Unknown error";
const executionId = error.execution?.id ?? "N/A";
return [{
  json: {
    text: "⚠️ *ShipWatch: Issue triage failed*\nExecution: " + executionId + "\nError: " + msg
  }
}];
